'use client';

import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { useGSAP } from '@gsap/react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { useTexture, MeshDistortMaterial, Float, useGLTF } from '@react-three/drei';

gsap.registerPlugin(ScrollTrigger);

// --- Shader Definitions (Unchanged) ---
const vertexShader = `
  uniform float uTime;
  uniform float uProgress; 
  varying vec2 vUv;
  varying float vElevation;

  void main() {
    vUv = uv;
    vec3 pos = position;

    float scrollLength = 10.0; 
    float rollPoint = (uProgress * 1.1 - 0.15) * scrollLength - (scrollLength / 2.0);

    if (pos.x > rollPoint) {
      float distancePastRoll = pos.x - rollPoint;
      float radius = 0.5; 
      float angle = distancePastRoll / radius;
      
      pos.x = rollPoint + sin(angle) * radius;
      pos.z = radius - cos(angle) * radius;
      pos.z += distancePastRoll * 0.01; 
    }
    
    float floatStrength = smoothstep(0.0, 0.2, uProgress);
    float wave = sin(pos.x * 2.0 + uTime) * 0.05 * floatStrength;
    pos.y += wave;

    vElevation = pos.z;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(pos, 1.0);
  }
`;

const fragmentShader = `
  uniform float uTime;
  uniform float uFade; 
  uniform sampler2D uTexture; 
  varying vec2 vUv;
  varying float vElevation;

  void main() {
    vec4 texColor = texture2D(uTexture, vUv);
    vec3 color = texColor.rgb;
    color = mix(color, vec3(0.96, 0.95, 0.92), 0.1); 
    float edgeAlpha = smoothstep(0.0, 0.1, vUv.y) * smoothstep(1.0, 0.9, vUv.y);
    float shadow = smoothstep(0.0, 0.5, vElevation); 
    color -= shadow * 0.3;
    gl_FragColor = vec4(color, uFade * edgeAlpha); 
  }
`;

// --- Real Model Component ---
function PineTreeModel() {
  const { scene } = useGLTF('/model-pine.glb');
  
  // Process the model to apply our "Ink Soul" material
  useMemo(() => {
    scene.traverse((child) => {
      if ((child as THREE.Mesh).isMesh) {
        const mesh = child as THREE.Mesh;
        mesh.castShadow = true;
        mesh.receiveShadow = true;
        // Apply a custom dark ink material
        mesh.material = new THREE.MeshStandardMaterial({
          color: '#1a1a1a', // Ink black
          emissive: '#0a0a0a',
          roughness: 0.3,   // Semi-glossy like wet ink
          metalness: 0.4,
        });
      }
    });
  }, [scene]);

  return (
    // Adjust scale and position based on model size
    <primitive object={scene} scale={[0.5, 0.5, 0.5]} position={[0, -0.5, 0]} />
  );
}

// --- Enhanced Ink Splash Component ---
function InkSplash() {
  const group = useRef<THREE.Group>(null);
  const dropRef = useRef<THREE.Mesh>(null);
  
  useGSAP(() => {
    if(!group.current || !dropRef.current) return;
    const tl = gsap.timeline({ delay: 0.2 });
    
    // 1. Drop falls
    tl.fromTo(dropRef.current.position, 
      { y: 4 }, 
      { y: 0.5, duration: 0.8, ease: "power2.in" }
    );
    
    // 2. Drop squashes and disappears
    tl.to(dropRef.current.scale, { x: 1.5, y: 0.1, z: 1.5, duration: 0.2 });
    tl.to(dropRef.current.material, { opacity: 0, duration: 0.1 }, "<");

    // 3. Fade out whole group on scroll
    ScrollTrigger.create({
      trigger: "body",
      start: "top top",
      end: "200px top",
      scrub: true,
      onUpdate: (self) => {
        if (group.current) {
           group.current.position.y = self.progress * 2;
           group.current.scale.setScalar(1 - self.progress);
           group.current.rotation.y = self.progress * 0.5;
        }
      }
    });
  }, []);

  return (
    <group ref={group}>
        {/* The Liquid Ink Drop (Initial State) */}
        <Float speed={2} rotationIntensity={0.5} floatIntensity={0.5}>
            <mesh ref={dropRef} position={[0, 4, 0]}>
                <sphereGeometry args={[0.3, 32, 32]} />
                <meshStandardMaterial 
                    color="#1a1a1a" 
                    roughness={0.1}
                    metalness={0.5}
                    transparent
                />
            </mesh>
        </Float>

        {/* The Tree growing from the ink */}
        <ModelWrapper />
    </group>
  );
}

function ModelWrapper() {
    const ref = useRef<THREE.Group>(null);
    useGSAP(() => {
        if(!ref.current) return;
        // Tree grows UP and SCALES UP
        gsap.fromTo(ref.current.scale, 
            { x: 0, y: 0, z: 0 }, 
            { x: 1, y: 1, z: 1, duration: 1.5, delay: 0.9, ease: "back.out(1.2)" }
        );
    }, []);

    return <group ref={ref}><PineTreeModel /></group>;
}

export default function ScrollModel() {
  const mesh = useRef<THREE.Mesh>(null);
  const progressRef = useRef({ value: 0 });
  const fadeRef = useRef({ value: 1 });

  const texture = useTexture('/scroll-texture.png');
  texture.minFilter = THREE.LinearFilter;
  texture.magFilter = THREE.LinearFilter;
  texture.colorSpace = THREE.SRGBColorSpace;

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0 },
      uProgress: { value: 0 },
      uFade: { value: 1 },
      uTexture: { value: texture },
    }),
    [texture]
  );

  useGSAP(() => {
    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: "body", 
        start: "top top",
        end: "bottom bottom",
        scrub: 1, 
      }
    });

    tl.to(progressRef.current, {
      value: 1,
      ease: "none"
    });

    ScrollTrigger.create({
      trigger: "#act-3-container", 
      start: "top center",
      end: "bottom top",
      onEnter: () => gsap.to(fadeRef.current, { value: 0.1, duration: 1 }),
      onLeave: () => gsap.to(fadeRef.current, { value: 1, duration: 1 }),
      onEnterBack: () => gsap.to(fadeRef.current, { value: 0.1, duration: 1 }),
      onLeaveBack: () => gsap.to(fadeRef.current, { value: 1, duration: 1 })
    });
  }, []);

  useFrame((state) => {
    if (mesh.current) {
      const material = mesh.current.material as THREE.ShaderMaterial;
      material.uniforms.uTime.value = state.clock.getElapsedTime();
      material.uniforms.uProgress.value = progressRef.current.value;
      material.uniforms.uFade.value = fadeRef.current.value;
    }
  });

  return (
    <group>
      <mesh ref={mesh} rotation={[0, 0, 0]}>
        <planeGeometry args={[10, 4, 128, 64]} /> 
        <shaderMaterial
          vertexShader={vertexShader}
          fragmentShader={fragmentShader}
          uniforms={uniforms}
          side={THREE.DoubleSide}
          transparent
          depthWrite={false}
        />
      </mesh>
      
      <InkSplash />
    </group>
  );
}
