'use client';

import { useRef, useMemo } from 'react';
import { useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = `
  uniform float uTime;
  uniform vec2 uMouse;
  uniform vec3 uColorBg;
  uniform vec3 uColorMist;
  varying vec2 vUv;

  // Simplex 2D noise
  vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
  float snoise(vec2 v){
    const vec4 C = vec4(0.211324865405187, 0.366025403784439,
             -0.577350269189626, 0.024390243902439);
    vec2 i  = floor(v + dot(v, C.yy) );
    vec2 x0 = v -   i + dot(i, C.xx);
    vec2 i1;
    i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
    vec4 x12 = x0.xyxy + C.xxzz;
    x12.xy -= i1;
    i = mod(i, 289.0);
    vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
    + i.x + vec3(0.0, i1.x, 1.0 ));
    vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
    m = m*m ;
    m = m*m ;
    vec3 x = 2.0 * fract(p * C.www) - 1.0;
    vec3 h = abs(x) - 0.5;
    vec3 ox = floor(x + 0.5);
    vec3 a0 = x - ox;
    m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
    vec3 g;
    g.x  = a0.x  * x0.x  + h.x  * x0.y;
    g.yz = a0.yz * x12.xz + h.yz * x12.yw;
    return 130.0 * dot(m, g);
  }

  // 水墨画效果 - 创建淡淡的水墨晕染
  void main() {
    float t = uTime * 0.05; // 缓慢流动
    
    // 创建多层水墨晕染效果
    // 第一层：大范围的山川轮廓
    vec2 uv1 = vUv * 3.0 + vec2(t * 0.1, t * 0.05);
    float n1 = snoise(uv1);
    float ink1 = smoothstep(0.4, 0.6, n1) * 0.15; // 淡淡的水墨
    
    // 第二层：中范围的云雾效果
    vec2 uv2 = vUv * 6.0 - vec2(t * 0.08, t * 0.12);
    float n2 = snoise(uv2);
    float ink2 = smoothstep(0.5, 0.7, n2) * 0.1;
    
    // 第三层：细节的墨点
    vec2 uv3 = vUv * 12.0 + vec2(t * 0.15, -t * 0.1);
    float n3 = snoise(uv3);
    float ink3 = smoothstep(0.6, 0.8, n3) * 0.08;
    
    // 第四层：远处的淡墨（营造深度）
    vec2 uv4 = vUv * 1.5 + vec2(-t * 0.05, t * 0.03);
    float n4 = snoise(uv4);
    float ink4 = smoothstep(0.3, 0.5, n4) * 0.12;
    
    // 组合所有水墨层
    float totalInk = ink1 + ink2 * 0.7 + ink3 * 0.5 + ink4;
    
    // 创建渐变效果（从中心向四周淡化）
    float dist = distance(vUv, vec2(0.5));
    float fade = 1.0 - smoothstep(0.3, 0.7, dist);
    totalInk *= fade;
    
    // 混合颜色：宣纸白 + 淡淡的水墨灰
    vec3 inkColor = mix(uColorBg, vec3(0.2, 0.2, 0.25), totalInk);
    
    // 添加微妙的暖色调（模拟宣纸的质感）
    inkColor = mix(inkColor, vec3(0.98, 0.97, 0.94), 0.3);
    
    // 边缘柔化
    float edgeFade = smoothstep(0.0, 0.1, vUv.x) * smoothstep(1.0, 0.9, vUv.x) *
                     smoothstep(0.0, 0.1, vUv.y) * smoothstep(1.0, 0.9, vUv.y);
    
    gl_FragColor = vec4(inkColor, edgeFade);
  }
`;

export default function Background() {
  const mesh = useRef<THREE.Mesh>(null);
  const { pointer, viewport } = useThree(); // Get mouse pointer (-1 to 1)
  
  const uniforms = useMemo(
    () => ({
      uTime: { value: 0 },
      uMouse: { value: new THREE.Vector2(0.5, 0.5) },
      // 宣纸白 - 带一点暖色调
      uColorBg: { value: new THREE.Color('#faf8f3') }, 
      // 淡淡的水墨灰
      uColorMist: { value: new THREE.Color('#d0d0d0') }, 
    }),
    []
  );

  useFrame((state) => {
    const { clock } = state;
    if (mesh.current) {
      const material = mesh.current.material as THREE.ShaderMaterial;
      material.uniforms.uTime.value = clock.getElapsedTime();
      
      // Convert pointer (-1 to 1) to UV space (0 to 1)
      // Note: This assumes the plane fills the screen perfectly, which it mostly does
      const x = (pointer.x + 1) * 0.5;
      const y = (pointer.y + 1) * 0.5;
      // Simple lerp for smooth mouse movement
      material.uniforms.uMouse.value.lerp(new THREE.Vector2(x, y), 0.1);
    }
  });

  return (
    <mesh ref={mesh} scale={[20, 12, 1]} position={[0, 0, -2]}> 
      <planeGeometry args={[1, 1]} />
      <shaderMaterial
        fragmentShader={fragmentShader}
        vertexShader={vertexShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}
